function render(t, context) {
  const { ctx, width: w, height: h, progress } = context;
  ctx.fillStyle = '#0d1117';
  ctx.fillRect(0, 0, w, h);
  ctx.save();
  ctx.translate(w / 2, h / 2);
  for (let i = 0; i < 48; i++) {
    const angle = i / 48 * Math.PI * 2 + t * 0.6;
    const radius = 90 + i * 4 + Math.sin(t + i) * 12;
    const x = Math.cos(angle) * radius;
    const y = Math.sin(angle) * radius * 0.52;
    ctx.fillStyle = i % 2 ? '#7bd88f' : '#ff5c8a';
    ctx.globalAlpha = 0.25 + progress * 0.7;
    ctx.beginPath();
    ctx.arc(x, y, 4 + (i % 5), 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.restore();
}

export default {
  render(t, context) {
    const { ctx, width: w, height: h, progress } = context;
    ctx.fillStyle = '#111318';
    ctx.fillRect(0, 0, w, h);
    ctx.save();
    ctx.translate(w / 2, h / 2);
    ctx.strokeStyle = '#f2aa4c';
    ctx.lineWidth = 8;
    ctx.globalAlpha = 0.5 + progress * 0.5;
    ctx.beginPath();
    ctx.roundRect(-260, -110, 520, 220, 28);
    ctx.stroke();
    ctx.fillStyle = '#ffffff';
    ctx.font = '700 48px Arial, sans-serif';
    ctx.textAlign = 'center';
    ctx.fillText('Runtime Core', 0, -8);
    ctx.font = '24px Arial, sans-serif';
    ctx.fillStyle = '#dfe9f5';
    ctx.fillText('timeline + code + video export', 0, 48);
    ctx.restore();
  }
}
